export function getQuestsByQuestline(): Map<string, Quest[]> {
  const map = new Map<string, Quest[]>();
  for (const q of quests) {
    if (!map.has(q.questline)) map.set(q.questline, []);
    map.get(q.questline)!.push(q);
  }
  return map;
}

export function getQuestsForLevel(level: number): Quest[] {
  return quests.filter(q => q.level <= level);
}

export function getQuestlinesForLevel(level: number): Map<string, Quest[]> {
  const filtered = getQuestsForLevel(level);
  const map = new Map<string, Quest[]>();
  for (const q of filtered) {
    if (!map.has(q.questline)) map.set(q.questline, []);
    map.get(q.questline)!.push(q);
  }
  return map;
}
